module gray_counter_core #(
    parameter integer WIDTH = 4
) (
    input  logic             clk,
    input  logic             rst_n,
    input  logic             enable,
    input  logic             clear,
    output logic [WIDTH-1:0] gray_value,
    output logic [WIDTH-1:0] bin_value,
    output logic             done
);

    // WIDTH constraint from SSOT error_handling. This is a build-time guard.
    localparam integer WIDTH_CHECK = (WIDTH >= 2) ? 1 : -1;

    // Architectural state variables owned by this module.
    logic [WIDTH-1:0] gray_state;
    logic [WIDTH-1:0] bin_state;
    logic             done_state;

    // Combinational decode/next-state helpers.
    logic [WIDTH-1:0] gray_to_bin_s1;
    logic [WIDTH-1:0] gray_to_bin_s2;
    logic [WIDTH-1:0] gray_to_bin_s3;
    logic [WIDTH-1:0] gray_to_bin_s4;
    logic [WIDTH-1:0] gray_to_bin_s5;
    logic [WIDTH-1:0] gray_to_bin_cur;
    logic [WIDTH-1:0] bin_next;
    logic [WIDTH-1:0] gray_next;
    logic             wrap_detect;

    // Gray->binary prefix XOR fold without loops/functions.
    assign gray_to_bin_s1  = gray_state ^ (gray_state >> 1);
    assign gray_to_bin_s2  = gray_to_bin_s1 ^ (gray_to_bin_s1 >> 2);
    assign gray_to_bin_s3  = gray_to_bin_s2 ^ (gray_to_bin_s2 >> 4);
    assign gray_to_bin_s4  = gray_to_bin_s3 ^ (gray_to_bin_s3 >> 8);
    assign gray_to_bin_s5  = gray_to_bin_s4 ^ (gray_to_bin_s4 >> 16);
    assign gray_to_bin_cur = gray_to_bin_s5 ^ (gray_to_bin_s5 >> 32);

    // GC_TXN_ADVANCE datapath: increment modulo 2^WIDTH and re-encode to Gray.
    assign bin_next    = gray_to_bin_cur + {{(WIDTH-1){1'b0}}, 1'b1};
    assign gray_next   = bin_next ^ (bin_next >> 1);
    assign wrap_detect = (gray_to_bin_cur == {WIDTH{1'b1}});

    // GC_TXN_RESET (async assert), then synchronous priority: clear > enable > hold.
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            gray_state <= {WIDTH{1'b0}};
            bin_state  <= {WIDTH{1'b0}};
            done_state <= 1'b0;
        end else begin
            if (clear) begin
                // GC_TXN_CLEAR: clear dominates enable on sampled edge.
                gray_state <= {WIDTH{1'b0}};
                bin_state  <= {WIDTH{1'b0}};
                done_state <= 1'b0;
            end else if (enable) begin
                // GC_TXN_ADVANCE: one-step Gray progression and one-cycle wrap pulse.
                gray_state <= gray_next;
                bin_state  <= bin_next;
                done_state <= wrap_detect;
            end else begin
                // GC_TXN_HOLD: keep state, force done low outside wrap cycle.
                gray_state <= gray_state;
                bin_state  <= gray_to_bin_cur;
                done_state <= 1'b0;
            end
        end
    end

    // Observable outputs: gray/done are registered; bin_value is combinational decode.
    assign gray_value = gray_state;
    assign done       = done_state;
    assign bin_value  = gray_to_bin_cur;

endmodule

